# نگاشتِ نرمال‌سازیِ حروف (عربی/فارسی) برای تطبیقِ درست
_LETTER_NORM = {
    'ي': 'ی', 'ى': 'ی', 'ئ': 'ی', 'ی': 'ی',
    'ك': 'ک', 'ک': 'ک',
    'أ': 'ا', 'إ': 'ا', 'آ': 'ا', 'ٱ': 'ا', 'ا': 'ا',
    'ة': 'ه', 'ه': 'ه', 'ۀ': 'ه',
    'ؤ': 'و',
}
# علائمِ اعراب/تشکیل که باید نادیده گرفته شوند
_AR_DIACRITICS = set(chr(c) for c in range(0x064B, 0x0653))
_AR_DIACRITICS |= {'\u0640', '\u0670', '\u0653', '\u0654', '\u0655', '\u0656', '\u0657', '\u0658'}


def norm_letter(ch):
    """یک حرف را به شکلِ نرمالِ فارسی برمی‌گرداند."""
    return _LETTER_NORM.get(ch, ch)


def is_muqatta_letter(ch):
    """آیا این حرف جزوِ ۱۴ حرفِ مقطعه است؟"""
    if not ch:
        return False
    return norm_letter(ch) in MUQATTAAT_SET


def clean_arabic(text):
    """حذفِ اعراب/تشکیل از متنِ عربی."""
    return ''.join(ch for ch in (text or '') if ch not in _AR_DIACRITICS)


def first_last_letters(text):
    """(حرفِ اول، حرفِ آخرِ) نرمال‌شدهٔ متنِ عربی؛ اعراب حذف می‌شود."""
    cleaned = clean_arabic(text)
    letters = [norm_letter(c) for c in cleaned
               if ('\u0621' <= c <= '\u064a') or c in ('ی', 'ک', 'پ', 'چ', 'ژ', 'گ')]
    if not letters:
        return None, None
    return letters[0], letters[-1]


