def parity_category(s):
    s = int(s); a = total_ayahs(s); so = s % 2; ao = a % 2
    if so and ao: return 'FF'
    if (not so) and (not ao): return 'ZZ'
    if so and (not ao): return 'FZ'
    return 'ZF'

def is_locked(s):
    return int(s) in EVENODD_LOCK_SET

def revelation(s):
    return EVENODD_REVELATION.get(int(s), '')

def is_makki(s):
    return EVENODD_REVELATION.get(int(s)) == 'مکی'

def evenodd_row(s):
    s = int(s)
    return {'surah': s, 'name': name(s), 'ayahs': total_ayahs(s), 'category': parity_category(s), 'revelation': revelation(s), 'locked': is_locked(s)}
